 1	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
 2	import { ContextMenu, Decorator, DEFAULT_DECORATOR_RADIUS as defaultDecoratorRadius } from '@patternfly/react-topology';
 3	import * as React from 'react';
 4	
 5	type Reference = React.ComponentProps<typeof ContextMenu>['reference'];
 6	
 7	type ClickableDecoratorProps = {
 8	  pos: { x: number; y: number };
 9	  icon: React.ReactElement;
10	  tooltip: string;
11	  isActive: boolean;
12	  onClick: (event: React.MouseEvent<SVGGElement, MouseEvent>) => void;
13	  padding?: number;
14	};
15	
16	export const ClickableDecorator: React.FC<ClickableDecoratorProps> = ({
17	  pos,
18	  icon,
19	  tooltip,
20	  isActive,
21	  onClick,
22	  padding
23	}) => {
24	  const ref = React.useRef<SVGGElement>(null);
25	
26	  return (
27	    <>
28	      <Decorator
29	        x={pos.x}
30	        y={pos.y}
31	        radius={defaultDecoratorRadius}
32	        padding={padding}
33	        showBackground
34	        icon={icon}
35	        className={isActive ? 'selected-decorator' : ''}
36	        onClick={onClick}
37	        innerRef={ref}
38	      />
39	      <Tooltip content={tooltip} position={TooltipPosition.right} triggerRef={ref} />
40	    </>
41	  );
42	};
43	
44	type ContextMenuDecoratorProps = Omit<ClickableDecoratorProps, 'onClick'> & {
45	  menuItems: React.ReactElement[];
46	};
47	
48	export const ContextMenuDecorator: React.FC<ContextMenuDecoratorProps> = props => {
49	  const [reference, setReference] = React.useState<Reference | null>(null);
50	  const onContextMenu = React.useCallback((e: React.MouseEvent) => {
51	    e.preventDefault();
52	    e.stopPropagation();
53	    setReference({ x: e.pageX, y: e.pageY });
54	  }, []);
55	
56	  return (
57	    <>
58	      <ClickableDecorator {...props} onClick={onContextMenu} />
59	      {reference ? (
60	        <ContextMenu reference={reference} open onRequestClose={() => setReference(null)}>
61	          {props.menuItems}
62	        </ContextMenu>
63	      ) : null}
64	    </>
65	  );
66	};

